import React, { useState, useEffect } from 'react';
import PropTypes from 'prop-types';
import Accordion from '../tools/finder__accordion';
import type { MultiCheckbox } from "../../types/filters/filters";

function Finder__MultiCheckbox(props: MultiCheckbox) {
    // Debug logs
  const { facet, query, dependencies, update } = props;
  const normalize = (v: string) => v.toLowerCase().trim().replace(/\s+/g, ' ');

  // Ensure we always treat the facet value as an array (Funnelback can return
  // a string for single values). This prevents length checks on strings and
  // gives a stable `initialChecked` count.
  const rawFacet = query.facets?.[facet.meta];
  const rawChecked = Array.isArray(rawFacet) ? rawFacet : rawFacet ? [rawFacet] : [];
  const initialChecked = rawChecked.length;

  const [checkTotal, setCheckTotal] = useState(initialChecked);

  // Keep internal `checkTotal` synced when `initialChecked` changes due to
  // incoming prop updates (component may mount with 0 then receive props
  // causing initialChecked to become non-zero).
  useEffect(() => {
    setCheckTotal(initialChecked);
  }, [initialChecked]);
  // Normalize values for comparison and state


  const rawSelected = query.facets?.[facet.meta];
  const selectedValues: string[] = Array.isArray(rawSelected)
    ? rawSelected.map(normalize)
    : rawSelected
    ? [normalize(rawSelected)]
    : [];

    // reduce the Funnelback response for the facet to an array of valid
    // values for the current query
  const responseFacets = props.responseFacet?.[0]?.allValues?.map((d) => d.data) ?? [];

  const handleChange = (value: string) => {
    const normValue = normalize(value);
      // clone query and facets (immutability)
    const newQuery = {
      ...query,
      facets: { ...query.facets }
    };
    newQuery.facets = { ...newQuery.facets };

      // clear dependent facets
    if (dependencies){
        dependencies.forEach((dep) => {
        delete newQuery.facets[dep.meta];
      });
    }

    const rawCurrent = newQuery.facets[facet.meta];
    const currentValues: string[] = Array.isArray(rawCurrent)
      ? rawCurrent.map(normalize)
      : rawCurrent
      ? [normalize(rawCurrent)]
      : [];

    // toggle value
    if (currentValues.includes(normValue)) {
      const updated = currentValues.filter(v => v !== normValue);
      if (updated.length > 0) {
          newQuery.facets[facet.meta] = updated;
      } else {
          // remove empty facet entry entirely
          delete newQuery.facets[facet.meta];
      }
      setCheckTotal(prev => prev - 1);
    } else {
      newQuery.facets[facet.meta] = [...currentValues, normValue];
      setCheckTotal(prev => prev + 1);
    }

    // reset paging / flags
    newQuery.startRank = 1;
    newQuery.misspelling = null;
    newQuery.interacted = true;

    update.query(newQuery);
    update.results(!update.updateState);
  };

  const multiCheckbox = facet.values?.map((value, i) => {
        const val = normalize(value.data);
        const isChecked = selectedValues.includes(val);
        const disable = responseFacets.includes(val) ? false : true;

        return (
          <div key={`${facet.meta}-${String(value.data)}`}>
            <input
              type="checkbox"
              id={val.replace(/\s+/g, '-')}
              name={`f±${facet.facetName}|${facet.meta}[]`}
              value={val}
              checked={isChecked}
              onChange={() => handleChange(val)}
              disabled={disable}
              data-test={isChecked}
            />
            <label className='v26-finder_filters__label--always' htmlFor={val.replace(/\s+/g, '-')}>{value.label}</label>
          </div>
        );
      }) || null;

  if(facet.accordion){
    return(
      <Accordion title={facet.name} matrixState={false} totalChecked={checkTotal}>
        {multiCheckbox}
      </Accordion>
    );
  } else{
    return (
      <div className="v26-finder__filter v26-finder__multiCheckbox">
        <legend>{facet.name}</legend>
        {multiCheckbox}
      </div>
    );
  }
  
}

Finder__MultiCheckbox.propTypes = {
  facet: PropTypes.object.isRequired,
  query: PropTypes.object.isRequired,
  dependencies: PropTypes.arrayOf(PropTypes.object),
  update: PropTypes.object.isRequired,
};

export default Finder__MultiCheckbox;
